"""Chainable data pipeline builder."""
from functools import reduce as _reduce
from typing import Any, Callable, Iterable, List, TypeVar

T = TypeVar('T')
U = TypeVar('U')


class Pipeline:
    def __init__(self, data: Iterable):
        self._data = data

    def map(self, func: Callable) -> 'Pipeline':
        return Pipeline(func(item) for item in self._data)

    def filter(self, predicate: Callable) -> 'Pipeline':
        return Pipeline(item for item in self._data if predicate(item))

    def reduce(self, func: Callable, initial: Any = None) -> Any:
        if initial is not None:
            return _reduce(func, self._data, initial)
        return _reduce(func, self._data)

    def collect(self) -> List:
        return list(self._data)

    def first(self) -> Any:
        return next(iter(self._data), None)

    def count(self) -> int:
        return sum(1 for _ in self._data)

    def take(self, n: int) -> 'Pipeline':
        def _take(data, limit):
            for i, item in enumerate(data):
                if i >= limit:
                    break
                yield item
        return Pipeline(_take(self._data, n))
